import React from 'react';
import { FadeIn, StaggerContainer, StaggerItem } from '../animations/MotionUtils';
import { Card, CardContent, CardHeader, CardTitle } from '../global/Card';
import { Input } from '../global/Input';
import { Button } from '../global/Button';

export const QuickInquiry = () => {
  return (
    <section className="py-20 bg-gray-50 dark:bg-slate-900">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="grid lg:grid-cols-2 gap-12 items-center">
          
          <FadeIn>
            <div>
              <h2 className="text-3xl font-bold tracking-tight mb-4">
                Not sure which course is right for you?
              </h2>
              <p className="text-lg text-gray-600 dark:text-gray-400 mb-8">
                Request a callback from our expert academic counselors. We'll help you chart the perfect roadmap for your educational journey.
              </p>
              
              <div className="flex gap-4 items-center">
                <div className="w-12 h-12 rounded-full bg-primary/10 flex items-center justify-center">
                  <svg className="w-6 h-6 text-primary" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 5a2 2 0 012-2h3.28a1 1 0 01.948.684l1.498 4.493a1 1 0 01-.502 1.21l-2.257 1.13a11.042 11.042 0 005.516 5.516l1.13-2.257a1 1 0 011.21-.502l4.493 1.498a1 1 0 01.684.949V19a2 2 0 01-2 2h-1C9.716 21 3 14.284 3 6V5z" />
                  </svg>
                </div>
                <div>
                  <p className="text-sm text-gray-500">Call us directly</p>
                  <p className="font-semibold">+91 123 456 7890</p>
                </div>
              </div>
            </div>
          </FadeIn>

          <FadeIn delay={0.2}>
            <Card className="shadow-lg border-primary/10">
              <CardHeader>
                <CardTitle className="text-2xl">Request Callback</CardTitle>
              </CardHeader>
              <CardContent>
                <form className="space-y-4">
                  <div className="grid grid-cols-2 gap-4">
                    <Input label="First Name" placeholder="John" />
                    <Input label="Last Name" placeholder="Doe" />
                  </div>
                  <Input label="Phone Number" type="tel" placeholder="+91 98765 43210" />
                  <Input label="Interested Class/Course" placeholder="e.g. 11th Science" />
                  <Button className="w-full mt-2" size="lg">Submit Inquiry</Button>
                </form>
              </CardContent>
            </Card>
          </FadeIn>

        </div>
      </div>
    </section>
  );
};
